import { defineComponentSlotStyle, focusRingStyle } from "@yamada-ui/react"

export const linkBoxStyle = defineComponentSlotStyle({
  base: {
    overlay: {
      focusVisibleRing: "none",
      position: "static",
      _before: {
        boxSize: "full",
        cursor: "inherit",
        display: "block",
        inset: "0",
        position: "absolute",
        zIndex: "0",
      },
      _focusVisible: { _before: focusRingStyle.outline },
    },
    root: {
      "a[href]:not([data-link-box-overlay]), abbr[title]": {
        position: "relative",
        zIndex: "yamcha",
      },
      position: "relative",
    },
  },
})

export type LinkBoxStyle = typeof linkBoxStyle

import type { FC } from "react"
import { a11y, page, render } from "#test/browser"
import { LinkBox } from "."
import { Heading } from "../heading"
import { Text } from "../text"

const Component: FC = () => {
  return (
    <LinkBox.Root data-testid="linkBox">
      <Heading>
        <LinkBox.Overlay
          href="https://yamada-ui.com"
          data-testid="linkBoxOverlay"
          external
        >
          Link Box
        </LinkBox.Overlay>
      </Heading>

      <Text>Description</Text>
    </LinkBox.Root>
  )
}

describe("<LinkBox />", () => {
  test("renders component correctly", async () => {
    await a11y(<Component />)
  })

  test("sets `displayName` correctly", () => {
    expect(LinkBox.Root.displayName).toBe("LinkBoxRoot")
    expect(LinkBox.Overlay.displayName).toBe("LinkBoxOverlay")
  })

  test("sets `className` correctly", async () => {
    await render(<Component />)

    await expect
      .element(page.getByTestId("linkBox"))
      .toHaveClass("ui-link-box__root")
    await expect
      .element(page.getByTestId("linkBoxOverlay"))
      .toHaveClass("ui-link-box__overlay")
  })

  test("renders HTML tag correctly", async () => {
    await render(<Component />)

    expect(page.getByTestId("linkBox").element().tagName).toBe("DIV")
    expect(page.getByTestId("linkBoxOverlay").element().tagName).toBe("A")
  })

  test("opens link in a new tab when external is true", async () => {
    await render(<Component />)

    const link = page.getByRole("link")

    await expect.element(link).toHaveAttribute("target", "_blank")
    await expect.element(link).toHaveAttribute("rel", "noopener")
  })
})

"use client"

import type { HTMLStyledProps, ThemeProps, Dict } from "@yamada-ui/react"
import type { LinkBoxStyle } from "./link-box.style"
import { createSlotComponent,
  radiusProperties,
  styled,
  useExtractProps, dataAttr } from "@yamada-ui/react"
import { linkBoxStyle } from "./link-box.style"

interface ComponentContext extends Dict {}

export interface LinkBoxRootProps
  extends HTMLStyledProps, ThemeProps<LinkBoxStyle> {}

const {
  ComponentContext,
  PropsContext: LinkBoxPropsContext,
  useComponentContext,
  usePropsContext: useLinkBoxPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<LinkBoxRootProps, LinkBoxStyle, ComponentContext>(
  "link-box",
  linkBoxStyle,
)

export { LinkBoxPropsContext, useLinkBoxPropsContext }

/**
 * `LinkBox` is a component that allows elements such as articles or cards to function as a single link.
 *
 * @see https://yamada-ui.com/docs/components/link-box
 */
export const LinkBoxRoot = withProvider<"div", LinkBoxRootProps>(
  ({ children, ...rest }) => {
    const context = useExtractProps(rest, radiusProperties)

    return (
      <ComponentContext value={context}>
        <styled.div {...rest}>{children}</styled.div>
      </ComponentContext>
    )
  },
  "root",
)()

export interface LinkBoxOverlayProps extends HTMLStyledProps<"a"> {
  /**
   * If `true`, the link will open in new tab.
   *
   * @default false
   */
  external?: boolean
}

export const LinkBoxOverlay = withContext<"a", LinkBoxOverlayProps>(
  "a",
  "overlay",
)(undefined, ({ external, _before, ...rest }) => {
  const context = useComponentContext()

  return {
    rel: external ? "noopener" : undefined,
    target: external ? "_blank" : undefined,
    "data-link-box-overlay": dataAttr(true),
    _before: { ..._before, ...context },
    ...rest,
  }
})

export {
  LinkBoxOverlay as Overlay,
  LinkBoxPropsContext as PropsContext,
  LinkBoxRoot as Root,
  useLinkBoxPropsContext as usePropsContext,
} from "./link-box"
export type {
  LinkBoxOverlayProps as OverlayProps,
  LinkBoxRootProps as RootProps,
} from "./link-box"
